mapper.select:
SELECT t.template_id, t.creator_user_id, t.title, t.scene_desc, t.current_version_id, t.price_type, t.price, t.shelf_status, t.use_count, t.favorite_count, t.avg_score, t.review_count, t.created_at, t.updated_at, COALESCE(v.prompt_content, t.scene_desc) AS summary FROM prompt_template t LEFT JOIN prompt_template_version v ON v.version_id = t.current_version_id WHERE t.shelf_status = 'ON_SHELF'
AND ( t.title LIKE CONCAT('%', #{req.keyword}, '%') OR t.scene_desc LIKE CONCAT('%', #{req.keyword}, '%') OR v.prompt_content LIKE CONCAT('%', #{req.keyword}, '%') )
AND t.avg_score >= #{req.minScore}
AND t.price >= #{req.minPrice}
AND t.price <= #{req.maxPrice}
AND EXISTS ( SELECT 1 FROM template_tag_rel r INNER JOIN tag tg ON tg.tag_id = r.tag_id WHERE r.template_id = t.template_id AND tg.tag_name = #{req.tag} )
ORDER BY t.created_at DESC, t.template_id DESC
ORDER BY t.avg_score DESC, t.use_count DESC, t.template_id DESC
ORDER BY t.use_count DESC, t.favorite_count DESC, t.avg_score DESC, t.template_id DESC
